(11, 'terminos_condiciones_servicio', '•PASADO 1 MES A PARTIR DE LA FECHA PREVISTA PARA LA DEVOLUCIÓN O LA FECHA EN LA QUE SE DEBIA RECHAZAR O ACEPTAR EL SERVICIO SIN QUE EL PROPIETARIO ACUDA A RETIRAR EL BIEN, SILICON LO REQUERIRA PARA QUE LO RETIRE DENTRO DE LOS DOS MESES SIGUIENTES, SI TRANSCURRIDO ESE TIEMPO NO SE RETIRA , EL BIEN SE ENTENDERA ABANDONADO POR LEY Y SE DARA EL TRATAMIENTO DESCRITO POR EL DECRETO 1413 DE 2018. <br /> • CUANDO EL ARTÍCULO ES REPARADO, LA REVISIÓN SE CONSIDERA COMO ABONO.<br /> • LA GARANTÍA ES DE 60 DÍAS A PARTIR DE LA FECHA DE ENTREGA. LA GARANTÍA INCLUYE ÚNICAMENTE LA MANO DE OBRA.<br /> • PARA RECLAMAR EL ARTÍCULO ES INDISPENSABLE PRESENTAR ESTE RECIBO O DENUNCIA POR PÉRDIDA DEL MISMO.<br /> • TODO APARATO ELECTRONICO CANCELA REVISIÓN, SIN EXEPCION.', 'Términos y Condiciones del Servicio', 'Texto legal para el ingreso de equipos', NULL, 'html', NULL, NULL, '2026-03-30 03:08:22', '2026-03-30 03:08:22'),
(12, 'terminos_condiciones_finales', '•PASADO 1 MES A PARTIR DE LA FECHA PREVISTA PARA LA DEVOLUCIÓN O LA FECHA EN LA QUE SE DEBIA RECHAZAR O ACEPTAR EL SERVICIO SIN QUE EL PROPIETARIO ACUDA A RETIRAR EL BIEN, SILICON LO REQUERIRA PARA QUE LO RETIRE DENTRO DE LOS DOS MESES SIGUIENTES, SI TRANSCURRIDO ESE TIEMPO NO SE RETIRA , EL BIEN SE ENTENDERA ABANDONADO POR LEY Y SE DARA EL TRATAMIENTO DESCRITO POR EL DECRETO 1413 DE 2018.<br /> • CUANDO EL ARTÍCULO ES REPARADO, LA REVISIÓN SE CONSIDERA COMO ABONO.<br /> • LA GARANTÍA ES DE 60 DÍAS A PARTIR DE LA FECHA DE ENTREGA. LA GARANTÍA INCLUYE ÚNICAMENTE LA MANO DE OBRA.<br /> • PARA RECLAMAR EL ARTÍCULO ES INDISPENSABLE PRESENTAR ESTE RECIBO O DENUNCIA POR PÉRDIDA DEL MISMO.<br /> • TODO APARATO ELECTRONICO CANCELA REVISIÓN, SIN EXEPCION.', 'Términos y Condiciones Finales', 'Texto legal para la entrega de equipos', NULL, 'html', NULL, NULL, '2026-03-30 03:08:22', '2026-03-30 03:08:22'),
(13, 'notificar_cada_dias', '2', 'Cada cuantos dias va enviar  mensaje de notificación', 'Cada cuantos dias va enviar  mensaje de notificación', NULL, 'entero', NULL, NULL, '2026-03-30 03:08:22', '2026-03-30 03:08:22'),
