INSERT INTO `reporte` (`id`, `grupo_reporte_id`, `reporte`, `descripcion`, `script`, `activo`, `nombre_archivo`, `user_id_create`, `user_id_update`, `creado_el`, `actualizado_el`) VALUES
(1, 1, 'Estado de las ordenes de servicio', 'Genera un extracto del estado de las órdenes de servicio al momento de la consulta. El usuario debe filtrar por estado y seleccionar un periodo de tiempo obligatorio para evitar la sobrecarga del sistema.', 'SELECT \n	o.id AS numero_orden,\n	o.creado_el,\n	s.sucursal ,\n    CASE WHEN o.distribuidor_id  IS NOT NULL THEN CONCAT_WS(\' \',d.distribuidor ,\'(\', md.municipio, \' - \', dp.departamento ,\')\') \n	ELSE NULL END AS distribuidor,\n	ts.tipo_servicio ,\n	IF(ts.es_garantia_marca,\'SÍ\',\'NO\') AS es_garantia ,\n	m.marca,\n	e.estado AS estado_orden,\n	CASE WHEN b.bodega IS NOT NULL THEN CONCAT_WS(\' \', b.bodega ,\'(\',mb.municipio ,\' - \', db.departamento ,\')\') \n	ELSE NULL END	AS bodega,\n	r.rack ,\n	o.ubicacion ,\n	ga.grupo_articulo ,\n	ta.tipo_articulo,\n	u.name AS tecnico,\n	c.identificacion ,\n	CONCAT_WS(\' \',c.nombres , c.apellidos) cliente,\n	o.modelo,\n	o.serie,\n	o.falla,\n	o.estado_del_articulo ,\n	o.tiempo_diagnostico,\n	o.tiempo_reparacion,\n	o.valor_total,\n	o.valor_respuestos,\n	o.valor_abono,\n	o.valor_pagado,\n	o.fecha_compra,\n	o.fecha_vence_garantia,\n	o.numero_factura,\n	o.numero_garantia,\n	o.numero_orden_marca\nFROM ordenes_servicio o \nJOIN tipos_articulos ta ON ta.id = o.tipo_articulo_id \nJOIN marcas m ON m.id = o.marca_id \nJOIN grupos_articulos ga ON ga.id = ta.grupo_id \nJOIN estados e ON e.id = o.estado_id \nJOIN users u ON u.id = o.tecnico_asignado_id \nJOIN clientes c ON c.id = o.cliente_id \nJOIN sucursales s ON s.id = o.sucursal_id \nJOIN tipos_servicio ts ON ts.id = o.tipo_servicio_id \nLEFT JOIN distribuidores d ON d.id = o.distribuidor_id \nLEFT JOIN municipios md ON md.id  = d.municipio_id \nLEFT JOIN departamentos dp ON dp.id = md.departamento_id \nLEFT JOIN racks r ON r.id = o.rack_id \nLEFT JOIN bodegas b ON b.id = r.bodega_id \nLEFT JOIN municipios mb ON mb.id = b.municipio_id \nLEFT JOIN departamentos db ON db.id = mb.departamento_id \nWHERE o.estado_id = ${estado_id}\nAND o.creado_el BETWEEN ${desde} AND ${hasta}', 1, 'ESTADO_ORDENES', 1, 1, '2026-03-17 21:05:28', '2026-03-17 23:01:52'),
(2, 1, 'Estado de las ordenes por sucursal', 'Genera un informe con la cantidad de órdenes de servicio según su estado actual, discriminando la información por sucursal.', 'SELECT 	\n    CONCAT(\' \', s.sucursal, \' (\', m.municipio, \' - \', d.departamento, \')\') AS sucursal_completa,\n    e.estado AS estado_orden,\n    COUNT(*) AS cantidad\nFROM ordenes_servicio o \nJOIN estados e ON e.id = o.estado_id \nJOIN sucursales s ON s.id = o.sucursal_id  \nJOIN municipios m ON m.id = s.municipio_id \nJOIN departamentos d ON d.id = m.departamento_id \nGROUP BY \n    s.sucursal, \n    m.municipio, \n    d.departamento, \n    e.estado', 1, 'ESTADOS_X_SUCURSAL', 1, 1, '2026-03-17 23:07:30', '2026-03-17 23:09:33'),
(3, 1, 'Tenicos x estado de orden', 'Este reporte permite obtener el estado de las ordenes discriminado por tecnicos.', 'SELECT \n	u.name AS tecnico,\n	e.estado AS estado_orden,\n	COUNT(*) AS cantidad\nFROM ordenes_servicio o  \nJOIN users u ON u.id = o.tecnico_asignado_id  \nJOIN estados e ON e.id = o.estado_id  \nWHERE o.sucursal_id  = ${sucursal_id}\nAND o.tipo_servicio_id  = ${tipo_servicio_id}\nGROUP BY u.name, e.estado', 1, 'TECNICOS_X_ESTADOS', 1, NULL, '2026-03-17 23:18:38', '2026-03-30 03:08:27'),
(4, 1, 'Estados de orden por marca', 'Este reporte optiene la cantidad de ordenes discriminado por marca y estado de la orden', 'SELECT 	\n	m.marca,\n	e.estado AS estado_orden,\n	COUNT(*) cantidad\nFROM ordenes_servicio o \nJOIN marcas m ON m.id = o.marca_id \nJOIN estados e ON e.id = o.estado_id  \nWHERE o.sucursal_id  = ${sucursal_id}\nAND o.tipo_servicio_id  = ${tipo_servicio_id}\nGROUP BY m.marca,	e.estado ', 1, 'ESTADOS_X_MARCA', 1, NULL, '2026-03-17 23:25:32', '2026-03-30 03:08:27'),
(5, 1, 'Ordenes de servicio por marca', 'Este reporte optiene las ordebes de servicio filtrado por marca y fechas ', 'SELECT \n	o.id AS numero_orden,\n	o.creado_el,\n	s.sucursal ,\n    CASE WHEN o.distribuidor_id  IS NOT NULL THEN CONCAT_WS(\' \',d.distribuidor ,\'(\', md.municipio, \' - \', dp.departamento ,\')\') \n	ELSE NULL END AS distribuidor,\n	ts.tipo_servicio ,\n	IF(ts.es_garantia_marca,\'SÍ\',\'NO\') AS es_garantia ,\n	m.marca,\n	e.estado AS estado_orden,\n	CASE WHEN b.bodega IS NOT NULL THEN CONCAT_WS(\' \', b.bodega ,\'(\',mb.municipio , \' - \', db.departamento ,\')\') \n	ELSE NULL END	AS bodega,\n	r.rack ,\n	o.ubicacion ,\n	ga.grupo_articulo ,\n	ta.tipo_articulo,\n	u.name AS tecnico,\n	c.identificacion ,\n	CONCAT_WS(\' \',c.nombres , c.apellidos) cliente,\n	o.modelo,\n	o.serie,\n	o.falla,\n	o.estado_del_articulo ,\n	o.tiempo_diagnostico,\n	o.tiempo_reparacion,\n	o.valor_total,\n	o.valor_respuestos,\n	o.valor_abono,\n	o.valor_pagado,\n	o.fecha_compra,\n	o.fecha_vence_garantia,\n	o.numero_factura,\n	o.numero_garantia,\n	o.numero_orden_marca\nFROM ordenes_servicio o \nJOIN tipos_articulos ta ON ta.id = o.tipo_articulo_id \nJOIN marcas m ON m.id = o.marca_id \nJOIN grupos_articulos ga ON ga.id = ta.grupo_id \nJOIN estados e ON e.id = o.estado_id \nJOIN users u ON u.id = o.tecnico_asignado_id \nJOIN clientes c ON c.id = o.cliente_id \nJOIN sucursales s ON s.id = o.sucursal_id \nJOIN tipos_servicio ts ON ts.id = o.tipo_servicio_id \nLEFT JOIN distribuidores d ON d.id = o.distribuidor_id \nLEFT JOIN municipios md ON md.id  = d.municipio_id \nLEFT JOIN departamentos dp ON dp.id = md.departamento_id \nLEFT JOIN racks r ON r.id = o.rack_id \nLEFT JOIN bodegas b ON b.id = r.bodega_id \nLEFT JOIN municipios mb ON mb.id = b.municipio_id \nLEFT JOIN departamentos db ON db.id = mb.departamento_id \nWHERE o.marca_id = ${marca_id}\nAND o.creado_el BETWEEN ${desde} AND ${hasta}', 1, 'ORDENES_X_MARCA', 1, NULL, '2026-03-17 23:32:26', '2026-03-30 03:08:27'),
(6, 1, 'Partes Solicitadas', 'Este reporte optiene las partes en estado SOLICITADAS filtrado por marca y fechas ', 'SELECT \n	os.id AS numero_orden,\n	p.creado_el AS fecha_orden,\n	p.articulo AS parte,\n	p.numero_parte ,\n	p.descripcion AS descripcio_parte,\n	p.observacion ,\n	p.valor AS valor_parte,\n	p.cantidad ,\n	p.estado AS estado_parte,\n	p.creado_el AS fecha_solicitud,\n	u.name AS solicitante\nFROM partes p \nJOIN ordenes_servicio os ON os.id = p.orden_servicio_id \nJOIN users u ON u.id = p.user_id_create \nWHERE p.estado = \'SOLICITADA\'\nAND DATE(p.creado_el) BETWEEN ${desde} AND ${hasta}', 1, 'PARTES_SOLICITADAS', 1, NULL, '2026-03-17 23:32:26', '2026-03-30 03:08:27');
INSERT INTO `reporte_parametro` (`id`, `reporte_id`, `tipo_parametro_id`, `parametro`, `script`, `max`, `min`, `requerido`, `etiqueta`, `user_id_create`, `user_id_update`, `creado_el`, `actualizado_el`) VALUES
(1, 1, 'Select', 'estado_id', 'SELECT id, estado AS value FROM estados', NULL, NULL, 1, 'ESTADO', 1, NULL, '2026-03-17 21:06:51', '2026-03-30 03:08:27'),
(2, 1, 'DateTimePicker', 'desde', NULL, NULL, NULL, 1, 'DESDE', 1, NULL, '2026-03-17 22:34:02', '2026-03-30 03:08:27'),
